spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    // Draw horizontal number line
    ctx.strokeStyle = '#374151';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(40, H / 2);
    ctx.lineTo(W - 40, H / 2);
    ctx.stroke();

    // Arrow heads
    ctx.fillStyle = '#374151';
    ctx.beginPath();
    ctx.moveTo(W - 40, H / 2);
    ctx.lineTo(W - 45, H / 2 - 5);
    ctx.lineTo(W - 45, H / 2 + 5);
    ctx.closePath();
    ctx.fill();

    ctx.beginPath();
    ctx.moveTo(40, H / 2);
    ctx.lineTo(45, H / 2 - 5);
    ctx.lineTo(45, H / 2 + 5);
    ctx.closePath();
    ctx.fill();

    // Draw integers 0 to 2
    var spacing = (W - 100) / 4;
    var intPositions = [];
    for (var i = 0; i <= 2; i++) {
      var x = 50 + i * spacing;
      intPositions.push({x: x, val: i});

      // Major tick and integer label
      ctx.strokeStyle = '#374151';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(x, H / 2 - 20);
      ctx.lineTo(x, H / 2 - 25);
      ctx.stroke();

      ctx.fillStyle = '#9CA3AF';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText(i.toString(), x, H / 2 - 40);

      // Integer circle
      ctx.fillStyle = '#10B981';
      ctx.beginPath();
      ctx.arc(x, H / 2, 10, 0, Math.PI * 2);
      ctx.fill();
    }

    // Draw fractions between integers
    ctx.strokeStyle = '#8B5CF6';
    ctx.lineWidth = 1;
    for (i = 0; i < intPositions.length - 1; i++) {
      var x1 = intPositions[i].x;
      var x2 = intPositions[i + 1].x;

      // Draw 1/3 and 2/3 between each integer
      var fractions = [{pos: 1/3, label: '1/3'}, {pos: 2/3, label: '2/3'}];
      fractions.forEach(function(frac, idx) {
        var fx = x1 + (x2 - x1) * frac.pos;

        // Highlight animation: pulse on each fraction
        var pulse = Math.sin(t * 0.06 + i * 0.5 + idx * 0.3) * 0.5 + 0.5;
        var radius = 6 + pulse * 2;

        ctx.fillStyle = '#8B5CF6';
        ctx.beginPath();
        ctx.arc(fx, H / 2, radius, 0, Math.PI * 2);
        ctx.fill();

        // Fraction label
        ctx.fillStyle = '#E9D5FF';
        ctx.font = 'bold 11px -apple-system, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(frac.label, fx, H / 2 - 28);
      });
    }
  }
};
